#!/bin/bash

# Extract PyCharm metadata script
# Outputs JSON with binary_path, display_name, version, and icon_paths

import json
import subprocess
import os
import glob

metadata = {
    "binary_path": "/opt/pycharm/bin/pycharm.sh",
    "binary_name": "pycharm.sh",
    "display_name": "PyCharm Community Edition",
    "desktop_entry": "/usr/share/applications/pycharm.desktop",
    "icon_paths": [],
    "version": None
}

# Try to get version from the installed PyCharm
try:
    version_file = "/opt/pycharm/build.txt"
    if os.path.exists(version_file):
        with open(version_file, 'r') as f:
            first_line = f.readline().strip()
            metadata["version"] = first_line
except:
    pass

# If version file doesn't have it, try a different approach
if not metadata["version"]:
    try:
        # Look for the version in the directory name or build files
        result = subprocess.run(["/opt/pycharm/bin/pycharm.sh", "--version"], 
                              capture_output=True, text=True, timeout=5)
        if result.stdout:
            # Extract version from output
            version_str = result.stdout.strip()
            # Usually outputs "PyCharm 2024.1"
            parts = version_str.split()
            if len(parts) > 1:
                metadata["version"] = parts[-1]
    except:
        pass

# If still no version, try to extract from installation directory
if not metadata["version"]:
    try:
        # Look for version in lib/pycharm.jar or other files
        pycharm_jar = glob.glob("/opt/pycharm/lib/pycharm-*.jar")
        if pycharm_jar:
            jar_name = os.path.basename(pycharm_jar[0])
            # Extract version from jar name like "pycharm-2024.1.jar"
            version_part = jar_name.replace("pycharm-", "").replace(".jar", "")
            metadata["version"] = version_part
    except:
        pass

# Default fallback version
if not metadata["version"]:
    metadata["version"] = "2024.1"

# Find icon files
icon_dirs = [
    "/opt/pycharm/bin/pycharm.png",
    "/opt/pycharm/lib/pycharm.png",
    "/opt/pycharm/lib/icons/",
]

# Check for common icon locations
for icon_dir in icon_dirs:
    if os.path.isfile(icon_dir):
        metadata["icon_paths"].append(icon_dir)
    elif os.path.isdir(icon_dir):
        # Look for PNG or SVG files in the directory
        for ext in ["*.png", "*.svg", "*.ico"]:
            pattern = os.path.join(icon_dir, ext)
            icons = glob.glob(pattern)
            metadata["icon_paths"].extend(icons)

# Check /usr/share/icons/
for icon_path in glob.glob("/usr/share/icons/*/apps/pycharm*"):
    if icon_path not in metadata["icon_paths"]:
        metadata["icon_paths"].append(icon_path)

# Check desktop file for icon
if os.path.exists(metadata["desktop_entry"]):
    try:
        with open(metadata["desktop_entry"], 'r') as f:
            for line in f:
                if line.startswith("Icon="):
                    icon_name = line.split("=", 1)[1].strip()
                    # Try to find the full path
                    if not icon_name.startswith("/"):
                        # Search in standard icon locations
                        search_paths = [
                            f"/usr/share/icons/hicolor/*/apps/{icon_name}.png",
                            f"/usr/share/pixmaps/{icon_name}.png",
                            f"/usr/share/pixmaps/{icon_name}.svg",
                        ]
                        for pattern in search_paths:
                            found = glob.glob(pattern)
                            if found:
                                metadata["icon_paths"].extend(found)
                    break
    except:
        pass

# Remove duplicates and sort
metadata["icon_paths"] = sorted(list(set(metadata["icon_paths"])))

# Output JSON
print(json.dumps(metadata, indent=2))

